import{kn as e}from"./chunk-IjxM6APl.js";var t=e(),n={author:[`fretchen`],order:5,title:`Tutorial 5 - Quantum simulation with cold atoms`};function r(e){let n={a:`a`,code:`code`,h2:`h2`,li:`li`,p:`p`,strong:`strong`,ul:`ul`,...e.components};return(0,t.jsxs)(t.Fragment,{children:[(0,t.jsxs)(n.p,{children:[`In the previous lessons we talked about `,(0,t.jsx)(n.a,{href:`qhw3`,children:`trapped ions`}),` and `,(0,t.jsx)(n.a,{href:`qhw4`,children:`superconducting qubits`}),`. They are the leading platforms for the creation of `,(0,t.jsx)(n.strong,{children:`universal quantum computers`}),`, which hold the premise of exponential speed-up for a variety of NP-hard problems. However, this universality usually comes at the price of algorithmic overhead for a wide range of tasks which generally leads to worse overall fidelity. If we give up the constraint of a universal quantum computer, we can build specialized quantum hardware for the problems of interest. Such systems are called\xA0quantum simulators. Cold atoms\xA0have become\xA0a leading platform of such quantum simulators at a large scale. Already demonstrated applications involve an enormous variety of condensed-matter problems like e.g. the `,(0,t.jsx)(n.a,{href:`https://journals.aps.org/rmp/abstract/10.1103/RevModPhys.80.885`,children:`Hubbard model`}),`, topological systems, `,(0,t.jsx)(n.a,{href:`https://www.sciencedirect.com/science/article/abs/pii/S1049250X06540017?via%3Dihub`,children:`superfluidity`}),` and `,(0,t.jsx)(n.a,{href:`https://physicstoday.scitation.org/doi/10.1063/1.3206091`,children:`disorder`}),`. More recently, cold atoms started to find applications to `,(0,t.jsx)(n.a,{href:`https://arxiv.org/abs/2002.07413`,children:`Ising models`}),` and `,(0,t.jsx)(n.a,{href:`https://royalsocietypublishing.org/doi/full/10.1098/rsta.2021.0064`,children:`high-energy physics`}),`.\xA0`]}),`
`,(0,t.jsx)(n.h2,{children:`Summary for the cold atoms hardware\xA0`}),`
`,(0,t.jsx)(n.p,{children:`Ultracold atoms are gases that are well isolated from the environment and are cooled to near zero and in this regard quite close to trapped ion systems, which also heavily draw on the experimental techniques of atomic physics and optics.\xA0At such low temperatures, quantum effects are dominant in the behavior of the gas cloud.\xA0Thanks to their precise control and flexibility, they are now a well-established platform for the quantum simulation of complex quantum problems.\xA0`}),`
`,(0,t.jsx)(n.p,{children:`The high precision and versatility have made cold atoms one of the dominating quantum hardware platforms in the European academic research sector. To underline the fact, in Heidelberg alone there are four research groups working with cold atoms. Munich, Hamburg and Bonn have similar numbers. France has at least 20 research groups on cold atoms, 1 on trapped ions and a handful on superconducting qubits. Similar numbers hold for Italy.`}),`
`,(0,t.jsx)(n.h2,{children:`Qubits based on Rydberg atoms`}),`
`,(0,t.jsxs)(n.ul,{children:[`
`,(0,t.jsxs)(n.li,{children:[(0,t.jsx)(n.strong,{children:`Use case`}),`: The same as trapped ions and superconducting qubits`]}),`
`,(0,t.jsxs)(n.li,{children:[(0,t.jsx)(n.strong,{children:`Companies`}),`: Pasqal, Quera, Atom Computing, ColdQuanta, planqc`]}),`
`,(0,t.jsxs)(n.li,{children:[(0,t.jsx)(n.strong,{children:`Research Groups`}),`: Paris, Harvard, Caltech, Munich, Heidelberg, â€¦\xA0`]}),`
`]}),`
`,(0,t.jsx)(n.p,{children:`The situation, which is closest to superconducting qubit systems are Rydberg quantum simulators. In these systems the atoms are confined in optical tweezer and strongly interact when they are excited into Rydberg states , as such implementing interacting qubit systems. They share many of features, which are similar to ions and superconducting qubits. The Hamiltonian, which is implemented in these systems, is a complex Ising type model:`}),`
`,(0,t.jsxs)(n.p,{children:[(0,t.jsx)(n.code,{className:`language-math math-inline`,children:`H=\\sum_i\\hat{\\sigma}_{x,i}+\\sum_iU_{ij}\\hat{n}_i\\hat{n}_j `}),`, with `,(0,t.jsx)(n.code,{className:`language-math math-inline`,children:`\\hat{\\sigma}_{x,i}=| râź©âź¨gâ€‹|_i+| gâź©âź¨râ€‹|_i`}),` and `,(0,t.jsx)(n.code,{className:`language-math math-inline`,children:`\\hat{n}_i=|râź©âź¨râ€‹|_i`}),`.`]}),`
`,(0,t.jsxs)(n.p,{children:[`They are currently, well established candidates for the quantum simulation of maximum-independent set problems, which already let to the foundation of the start-ups `,(0,t.jsx)(n.a,{href:`https://pasqal.io/`,children:`Pasqal`}),`, `,(0,t.jsx)(n.a,{href:`https://www.quera.com/`,children:`Quera`}),`, `,(0,t.jsx)(n.a,{href:`https://atom-computing.com/`,children:`Atom Computing`}),`, `,(0,t.jsx)(n.a,{href:`https://coldquanta.com/`,children:`ColdQuanta`}),` or `,(0,t.jsx)(n.a,{href:`https://www.planqc.eu/`,children:`planqc`}),`.`]}),`
`,(0,t.jsx)(n.h2,{children:`Itinerant particles\xA0built from cold atoms`}),`
`,(0,t.jsxs)(n.ul,{children:[`
`,(0,t.jsxs)(n.li,{children:[(0,t.jsx)(n.strong,{children:`Use case`}),`: Condensed matter, chemistry`]}),`
`,(0,t.jsxs)(n.li,{children:[(0,t.jsx)(n.strong,{children:`Research Groups`}),`: Munich, Heidelberg, Zurich, Harvard, â€¦\xA0`]}),`
`,(0,t.jsxs)(n.li,{children:[(0,t.jsx)(n.strong,{children:`Representable as circuit`}),`: Yes`]}),`
`]}),`
`,(0,t.jsx)(n.p,{children:`The most widely used configuration of cold atoms are moving atoms in some external optical potential. The atomic clouds are typically trapped by focused laser beams, which can be shaped in a flexible fashion. As such a wide variety of systems exists:`}),`
`,(0,t.jsxs)(n.ul,{children:[`
`,(0,t.jsx)(n.li,{children:`Traps with hundreds of thousands of atoms, which emulate superfluid behavior and Bose-Einstein condensation.`}),`
`,(0,t.jsx)(n.li,{children:`Traps with hundreds of atoms for the study of continuous variables and large-scale entanglement.`}),`
`,(0,t.jsx)(n.li,{children:`Optical lattices from the interference of laser beams are now widely used for the study of lattice models in condensed matter with system sizes well above the 100 sites and atoms.`}),`
`]}),`
`,(0,t.jsx)(n.p,{children:`Additionally, the quantum statistics can be tuned widely:`}),`
`,(0,t.jsxs)(n.ul,{children:[`
`,(0,t.jsx)(n.li,{children:`Working with fermionic or bosonic isotopes the atoms can directly emulate fermionic or bosonic problems.`}),`
`,(0,t.jsx)(n.li,{children:`If a large number of bosons are condensed into a single spatial mode they can form large collective spins, i.e. continuous variables, from their internal degrees of freedom.`}),`
`,(0,t.jsx)(n.li,{children:`The connection between moving particles and spin degrees leads to a variety of exotic behaviors like topological band structures, if needed.`}),`
`]}),`
`,(0,t.jsx)(n.p,{children:`The particles are interacting in various ways:`}),`
`,(0,t.jsxs)(n.ul,{children:[`
`,(0,t.jsx)(n.li,{children:`Most Alkali based system are described through a simple contact interaction.`}),`
`,(0,t.jsx)(n.li,{children:`Alkaline-earth atoms and Rydberg systems have long range interactions.`}),`
`]}),`
`,(0,t.jsx)(n.p,{children:`The readout of the system can be performed in various fashion:`}),`
`,(0,t.jsxs)(n.ul,{children:[`
`,(0,t.jsx)(n.li,{children:`Spatially resolved fluorescence imaging provides a destructive, state-sensitive readout.\xA0`}),`
`,(0,t.jsx)(n.li,{children:`Depending on the measurement protocol momentum or position can be measured.`}),`
`,(0,t.jsx)(n.li,{children:`[Dispersive measurements allow for weak measurement protocols.`}),`
`]}),`
`,(0,t.jsx)(n.p,{children:`If the external potential is an optical lattice they provide a synthetic realization of strongly correlated lattice models as visualized in Figure 2.`}),`
`,(0,t.jsx)(n.p,{children:`Nowadays, the systems are used for the study of quantum dynamics with quench protocols very similar to quantum computation systems as visualized on the right-hand side of the figure. Those experiments realize the Hubbard model:`}),`
`,(0,t.jsx)(n.p,{children:(0,t.jsx)(n.code,{className:`language-math math-inline`,children:`H= -J\\sum_i(\\hat{c}_{i+1}^\\dagger \\hat{c}_i+h.c.) +\\frac{U}{2}\\sum_i \\hat{n}_i(\\hat{n}_i-1)`})}),`
`,(0,t.jsx)(n.p,{children:`As such they have been widely employed for the study of many-body problems, which come originally from condensed matter. In the early stages this was used to study ground state properties of complex systems like unitary fermions or strongly correlated lattice systems. Importantly, experiments have gone well into the regime of non-perturbative theories. They are therefore well-established benchmarks for sophisticated numerical techniques, which would be otherwise uncontrolled.`}),`
`,(0,t.jsxs)(n.p,{children:[`Currently, this kind of quench experiments have to be completely programmed at the hardware level. However, with `,(0,t.jsx)(n.a,{href:`https://qiskit-extensions.github.io/qiskit-cold-atom/tutorials/03_fermionic_tweezer_hardware.html`,children:`qiskit-cold-atoms`}),` it is now possible to emulate such problems and a hardware integration seems only like a question of time.`]}),`
`,(0,t.jsx)(n.h2,{children:`Application to quantum chemistry`}),`
`,(0,t.jsx)(n.p,{children:`As IBM already demonstrated beautifully in previous experiments, molecular systems are made for the study of NISQ devices. However, the translation of the fermionic electrons on Qubits currently involves complex transformations like the Jordan-Wigner transformation. These can lead to substantial overhead and substantially increase the required circuit depth. Using fermionic atoms in microtraps, we directly emulate the chemistry problem onto the hardware.`}),`
`,(0,t.jsx)(n.p,{children:`In these systems the molecule is translated into its orbital basis. Each orbit is then represented by the occupation of a fermion of an optical tweezer. These fermionic systems are described by a hopping term HJand a non-commuting interaction term HU. As such they become a potential resource for variational algorithms, which again would heavily benefit from an integration.`}),`
`,(0,t.jsx)(n.p,{children:`These systems are also excellent candidates for the quantum simulation of chemistry problems as they naturally realize interacting fermions on different spatial orbits.`}),`
`,(0,t.jsx)(n.p,{children:`Mixed integer problems in atomic mixtures`}),`
`,(0,t.jsx)(n.p,{children:`Use cases: High-energy physics. Power plant optimization`}),`
`,(0,t.jsx)(n.p,{children:`Research Groups: MIT, Heidelberg, Karlsruhe, Harvard, JILA\xA0`}),`
`,(0,t.jsx)(n.p,{children:`Atomic mixtures are an extension to cold atoms as the provide the ability to let two independent atomic species interact. As such they are an ideal platform to study complex problems, which are defined on complex computational sectors as we describe for lattice gauge theories.\xA0`}),`
`,(0,t.jsx)(n.p,{children:`In the fundamental laws of physics, gauge fields mediate the interaction between charged particles. An example is quantum electrodynamicsâ€”the theory of electrons interacting with the electromagnetic fieldâ€”based on U(1) gauge symmetry. Solving such gauge theories is in general a hard problem for classical computational techniques. While quantum computers suggest a way forward, it is difficult to build large-scale digital quantum devices required for complex simulations. In cold atoms, we work on a fully scalable analog quantum simulator of a U(1) gauge theory in one spatial dimension. Some experiments demonstrated the experimental realization of the elementary building block as a key step towards a platform for large-scale quantum simulations of continuous gauge theories.`}),`
`,(0,t.jsxs)(n.p,{children:[`In the experiments one atomic species emulates the gauge fields described by the Hamiltonian `,(0,t.jsx)(n.code,{className:`language-math math-inline`,children:`H_g`}),` and the other species the matter field with Hamiltonian `,(0,t.jsx)(n.code,{className:`language-math math-inline`,children:`H_m`}),`, interacting through a coupling Hamiltonian `,(0,t.jsx)(n.code,{className:`language-math math-inline`,children:`H_{mg}`}),`. In the typical experiments the gauge field is tuned through an x-rotation and then the system is left to evolve under the full Hamiltonian `,(0,t.jsx)(n.code,{className:`language-math math-inline`,children:`H=H_g+H_m+H_{mg}`}),` :`]}),`
`,(0,t.jsx)(n.p,{children:(0,t.jsx)(n.code,{className:`language-math math-inline`,children:`H= \\chi \\sum_ i\\hat{L}_{z,i}^2+M\\sum_i (-1)^i\\hat{n}_i+J\\sum_i(\\hat{c}_{i+1}^\\dagger\\hat{L}_{+,i}\\hat{c}_i+h.c. )`})}),`
`,(0,t.jsxs)(n.p,{children:[`These Hamiltonian are extremely demanding computationally as the gauge field is defined on the Hilbert space of a `,(0,t.jsx)(n.a,{href:`qhw2`,children:`continuous variable`}),` `,(0,t.jsx)(n.code,{className:`language-math math-inline`,children:`L`}),` and the matter field on the Hilbert space of itinerant fermions. As such it presents a physical example of a NP-hard mixed-integer problem.`]}),`
`,(0,t.jsxs)(n.p,{children:[`Again, this kind of experiments have to be completely programmed at the hardware level. Quite importantly, this translation currently requires a good knowledge of the hardware from all participants, even high-energy physicists. This makes the experiments currently extremely cumbersome to translate from atomic physics to high-energy physics and back. As such they are one of the interesting use cases that drove the development of `,(0,t.jsx)(n.a,{href:`https://github.com/Qiskit-Extensions/qiskit-cold-atom`,children:`qiskit-cold-atoms`}),`.`]}),`
`,(0,t.jsx)(n.h2,{children:`Machine learning and power plant optimization`}),`
`,(0,t.jsxs)(n.p,{children:[`Machine learning algorithms heavily draw on similar problems like chemistry as they attempt to optimize energy functionals. However, in those problems some of the variables are typically `,(0,t.jsx)(n.a,{href:`qhw2`,children:`continuous variables`}),` and some `,(0,t.jsx)(n.a,{href:`qhw1`,children:`binary`}),`. These mixed-integer optimization problems are NP hard to solve on classical hardware. The continuous variables on the other hand make them extremely resource intensive for qubit-based systems. Cold atoms show a way forward to employ continuous variables and qubits directly into the system and employ a variational algorithm on them.\xA0Similar problems arise for power plant optimizations, when the power plant can give certain power outputs above a certain threshold. Both topics are under active investigation, but currently suffer from the lack of an intermediate programming layer between the users and the hardware developers.`]}),`
`,(0,t.jsx)(n.h2,{children:`Summary`}),`
`,(0,t.jsx)(n.p,{children:`This is the last lesson of this course. You learned:`}),`
`,(0,t.jsxs)(n.ul,{children:[`
`,(0,t.jsx)(n.li,{children:`That cold atoms have become one of the leading quantum simulation platforms.`}),`
`,(0,t.jsx)(n.li,{children:`Rydberg atoms can implement qubit systems, which are similar to trapped ions of superconducting qubits.`}),`
`,(0,t.jsx)(n.li,{children:`Cold atoms can easily tackle complex problems with itinerant particles.`}),`
`]})]})}function i(e={}){let{wrapper:n}=e.components||{};return n?(0,t.jsx)(n,{...e,children:(0,t.jsx)(r,{...e})}):r(e)}export{i as default,n as frontmatter};